// src/History.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com"; // backend URL
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function History({ employee }) {
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [bills, setBills] = useState([]);

  const [activeTab, setActiveTab] = useState("travel"); // "travel" | "ticket"

  // filters
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [minAmount, setMinAmount] = useState("");
  const [maxAmount, setMaxAmount] = useState("");

  const navigate = useNavigate();

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes, bRes] = await Promise.all([
        fetch(
          `${apiBase}/travel-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(
          `${apiBase}/ticket-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(`${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`),
      ]);

      const [travel, tickets, billsData] = await Promise.all([
        tRes.json(),
        kRes.json(),
        bRes.json(),
      ]);

      setTravelExpenses(Array.isArray(travel) ? travel : []);
      setTicketExpenses(Array.isArray(tickets) ? tickets : []);
      setBills(Array.isArray(billsData) ? billsData : []);
    } catch (err) {
      console.error("History fetch error:", err);
      setTravelExpenses([]);
      setTicketExpenses([]);
      setBills([]);
    }
  };

  // ---------- FILTER LOGIC ----------
  const applyFilters = (items, type) => {
    return items.filter((item) => {
      // pick correct date field
      const rawDate =
        type === "travel"
          ? item.travel_date
          : type === "ticket"
          ? item.ticket_date
          : item.created_at;

      const dateString = rawDate?.split?.("T")?.[0] || rawDate;
      const amt = Number(item.amount || 0);

      // date filters
      if (startDate && dateString && dateString < startDate) return false;
      if (endDate && dateString && dateString > endDate) return false;

      // amount filters
      if (minAmount && !isNaN(minAmount) && amt < Number(minAmount))
        return false;
      if (maxAmount && !isNaN(maxAmount) && amt > Number(maxAmount))
        return false;

      return true;
    });
  };

  const filteredTravel = applyFilters(travelExpenses, "travel");
  const filteredTicket = applyFilters(ticketExpenses, "ticket");

  // ---------- EDIT / DELETE HANDLERS ----------
  const deleteTravel = async (id) => {
    if (!window.confirm("Delete this travel record?")) return;

    try {
      const res = await fetch(`${apiBase}/travel-expenses/${id}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        alert("Failed to delete travel record");
        return;
      }

      setTravelExpenses((prev) => prev.filter((t) => t.id !== id));
    } catch (err) {
      console.error("Delete travel error:", err);
      alert("Error deleting travel record");
    }
  };

  const deleteTicket = async (id) => {
    if (!window.confirm("Delete this ticket record?")) return;

    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${id}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        alert("Failed to delete ticket record");
        return;
      }

      setTicketExpenses((prev) => prev.filter((t) => t.id !== id));
    } catch (err) {
      console.error("Delete ticket error:", err);
      alert("Error deleting ticket record");
    }
  };

  const editTravel = async (row) => {
    const newDate =
      window.prompt("Travel Date (YYYY-MM-DD):", row.travel_date?.split?.("T")?.[0] || row.travel_date) ||
      row.travel_date;
    const newPurpose =
      window.prompt("Purpose:", row.purpose) || row.purpose;
    const newFrom =
      window.prompt("From:", row.location_from || row.from) ||
      row.location_from ||
      row.from;
    const newTo =
      window.prompt("To:", row.location_to || row.to) ||
      row.location_to ||
      row.to;
    const newAmount =
      window.prompt("Amount:", row.amount) || row.amount;

    try {
      const res = await fetch(`${apiBase}/travel-expenses/${row.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          travel_date: newDate,
          purpose: newPurpose,
          location_from: newFrom,
          location_to: newTo,
          amount: newAmount,
        }),
      });

      if (!res.ok) {
        alert("Failed to update travel record");
        return;
      }

      setTravelExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                travel_date: newDate,
                purpose: newPurpose,
                location_from: newFrom,
                location_to: newTo,
                amount: newAmount,
              }
            : t
        )
      );
    } catch (err) {
      console.error("Update travel error:", err);
      alert("Error updating travel record");
    }
  };

  const editTicket = async (row) => {
    const newDate =
      window.prompt("Ticket Date (YYYY-MM-DD):", row.ticket_date?.split?.("T")?.[0] || row.ticket_date) ||
      row.ticket_date;
    const newPurpose =
      window.prompt("Purpose:", row.purpose) || row.purpose;
    const newAssigned =
      window.prompt("Assigned To:", row.assigned_to) || row.assigned_to;
    const newAmount =
      window.prompt("Amount:", row.amount) || row.amount;

    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${row.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ticket_date: newDate,
          purpose: newPurpose,
          assigned_to: newAssigned,
          amount: newAmount,
        }),
      });

      if (!res.ok) {
        alert("Failed to update ticket record");
        return;
      }

      setTicketExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                ticket_date: newDate,
                purpose: newPurpose,
                assigned_to: newAssigned,
                amount: newAmount,
              }
            : t
        )
      );
    } catch (err) {
      console.error("Update ticket error:", err);
      alert("Error updating ticket record");
    }
  };

  // ---------- DOWNLOAD PDF (simple: print page) ----------
  const handleDownloadPDF = () => {
    window.print(); // opens browser print → user can save as PDF
  };

  if (!employee) {
    return (
      <div
        style={{
          minHeight: "100vh",
          background: lightGreen,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontFamily: "Segoe UI",
        }}
      >
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI",
      }}
    >
      <div
        style={{
          maxWidth: 950,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
        }}
      >
        {/* Back + Title */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 8,
          }}
        >
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: green,
              fontSize: 16,
              cursor: "pointer",
            }}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginBottom: 12 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Filters + Download */}
        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: 10,
            alignItems: "center",
            marginBottom: 14,
            background: "#f9fff9",
            borderRadius: 10,
            padding: 10,
            border: "1px solid #eaf8f0",
          }}
        >
          <div style={{ display: "flex", flexDirection: "column", fontSize: 12 }}>
            <span>From Date</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInputStyle}
            />
          </div>

          <div style={{ display: "flex", flexDirection: "column", fontSize: 12 }}>
            <span>To Date</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInputStyle}
            />
          </div>

          <div style={{ display: "flex", flexDirection: "column", fontSize: 12 }}>
            <span>Min Amount</span>
            <input
              type="number"
              value={minAmount}
              onChange={(e) => setMinAmount(e.target.value)}
              placeholder="0"
              style={filterInputStyle}
            />
          </div>

          <div style={{ display: "flex", flexDirection: "column", fontSize: 12 }}>
            <span>Max Amount</span>
            <input
              type="number"
              value={maxAmount}
              onChange={(e) => setMaxAmount(e.target.value)}
              placeholder="Any"
              style={filterInputStyle}
            />
          </div>

          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
              setMinAmount("");
              setMaxAmount("");
            }}
            style={{
              padding: "6px 10px",
              borderRadius: 8,
              border: "1px solid #ccc",
              background: "#fff",
              fontSize: 12,
              cursor: "pointer",
            }}
          >
            Clear Filters
          </button>

          <button
            onClick={handleDownloadPDF}
            style={{
              marginLeft: "auto",
              padding: "8px 14px",
              borderRadius: 20,
              border: "none",
              background: green,
              color: "#fff",
              fontSize: 13,
              cursor: "pointer",
            }}
          >
            Download PDF
          </button>
        </div>

        {/* Tabs */}
        <div
          style={{
            display: "flex",
            gap: 8,
            marginBottom: 12,
          }}
        >
          <button
            onClick={() => setActiveTab("travel")}
            style={{
              flex: 1,
              padding: "8px 0",
              borderRadius: 20,
              border: activeTab === "travel" ? "none" : "1px solid #ccc",
              background: activeTab === "travel" ? green : "#ffffff",
              color: activeTab === "travel" ? "#fff" : "#333",
              cursor: "pointer",
              fontSize: 13,
              fontWeight: 600,
            }}
          >
            Travel History
          </button>
          <button
            onClick={() => setActiveTab("ticket")}
            style={{
              flex: 1,
              padding: "8px 0",
              borderRadius: 20,
              border: activeTab === "ticket" ? "none" : "1px solid #ccc",
              background: activeTab === "ticket" ? green : "#ffffff",
              color: activeTab === "ticket" ? "#fff" : "#333",
              cursor: "pointer",
              fontSize: 13,
              fontWeight: 600,
            }}
          >
            Ticket History
          </button>
        </div>

        {/* TAB CONTENT */}
        {activeTab === "travel" && (
          <>
            <h3 style={{ color: green, marginTop: 8 }}>Travel Expense History</h3>
            <table style={tableStyle()}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Purpose</th>
                  <th>Amount</th>
                  <th>From</th>
                  <th>To</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredTravel.map((t) => (
                  <tr key={t.id}>
                    <td>
                      {t.travel_date?.split?.("T")?.[0] || t.travel_date}
                    </td>
                    <td>{t.purpose}</td>
                    <td>₹{t.amount}</td>
                    <td>{t.location_from || t.from}</td>
                    <td>{t.location_to || t.to}</td>
                    <td>
                      <button
                        onClick={() => editTravel(t)}
                        style={actionBtnStyle}
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => deleteTravel(t.id)}
                        style={{ ...actionBtnStyle, borderColor: "#c62828", color: "#c62828" }}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
                {filteredTravel.length === 0 && (
                  <tr>
                    <td colSpan="6" style={{ textAlign: "center", padding: 10 }}>
                      No travel records match your filters.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </>
        )}

        {activeTab === "ticket" && (
          <>
            <h3 style={{ color: green, marginTop: 8 }}>Ticket Expense History</h3>
            <table style={tableStyle()}>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Purpose</th>
                  <th>Assigned To</th>
                  <th>Amount</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredTicket.map((t) => (
                  <tr key={t.id}>
                    <td>
                      {t.ticket_date?.split?.("T")?.[0] || t.ticket_date}
                    </td>
                    <td>{t.purpose}</td>
                    <td>{t.assigned_to}</td>
                    <td>₹{t.amount}</td>
                    <td>
                      <button
                        onClick={() => editTicket(t)}
                        style={actionBtnStyle}
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => deleteTicket(t.id)}
                        style={{ ...actionBtnStyle, borderColor: "#c62828", color: "#c62828" }}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
                {filteredTicket.length === 0 && (
                  <tr>
                    <td colSpan="5" style={{ textAlign: "center", padding: 10 }}>
                      No ticket records match your filters.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </>
        )}

        {/* Bills — keep as is, below tabs */}
        <h3 style={{ color: green, marginTop: 20 }}>Bills Upload History</h3>
        <table style={tableStyle()}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
            </tr>
          </thead>
          <tbody>
            {bills.map((b) => (
              <tr key={b.id}>
                <td>{b.created_at?.split?.("T")?.[0] || b.created_at}</td>
                <td>{b.fileName || b.filename}</td>
                <td>
                  {b.filePath && (
                    <a
                      href={`${apiBase}${b.filePath}`}
                      target="_blank"
                      rel="noreferrer"
                    >
                      Open
                    </a>
                  )}
                </td>
              </tr>
            ))}
            {bills.length === 0 && (
              <tr>
                <td colSpan="3" style={{ textAlign: "center", padding: 10 }}>
                  No bills uploaded yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function tableStyle() {
  return {
    width: "100%",
    borderCollapse: "collapse",
    fontSize: 13,
  };
}

const filterInputStyle = {
  padding: "4px 6px",
  borderRadius: 6,
  border: "1px solid #ccc",
  fontSize: 12,
};

const actionBtnStyle = {
  padding: "3px 8px",
  marginRight: 6,
  borderRadius: 6,
  border: "1px solid " + green,
  background: "#fff",
  fontSize: 11,
  cursor: "pointer",
  color: green,
};
